let weakMap2 = new WeakMap();

(function () {
  let obj1 = { id: 1 };
  let obj2 = { id: 2 };

  map2.set(obj1, 'data1');
  weakMap2.set(obj2, 'data2');

  // \u51FD\u6570\u7ED3\u675F\u65F6\uFF0Cobj1 \u548C obj2 \u7684\u5C40\u90E8\u5F15\u7528\u90FD\u4F1A\u6D88\u5931
  // Map \u4E2D\u7684 obj1 \u4F5C\u4E3A\u952E\uFF0C\u901A\u5E38\u4F1A\u4E00\u76F4\u5B58\u6D3B\uFF08\u9664\u975E\u624B\u52A8\u5220\u9664\uFF09
  // WeakMap \u4E2D\u7684 obj2 \u4F5C\u4E3A\u952E\uFF0C\u5728\u53D8\u4E3A\u4E0D\u53EF\u8FBE\u540E\uFF0C\u6709\u8D44\u683C\u88AB\u5783\u573E\u56DE\u6536
})();

// \u6B64\u65F6\uFF1A
