// - weakMap2 \u4E2D\u4E0E obj2 \u5BF9\u5E94\u7684\u6570\u636E\uFF0C\u53EF\u80FD\u5DF2\u7ECF\u88AB\u6E05\u7406\uFF0C\u4E5F\u53EF\u80FD\u5C1A\u672A\u6E05\u7406
